solution.approach:
For a query (L,R) the number added to city i (L ≤ i ≤ R) is i‑L+1 = i·1 + (1‑L). So each query contributes a coefficient of 1 to every position in [L,R] and a constant (1‑L). We keep two difference arrays: coeffDiff for the coefficient of i and constDiff for the constant term. For each query we do:
    coeffDiff[L] += 1; coeffDiff[R+1] -= 1;
    constDiff[L] += (1‑L); constDiff[R+1] -= (1‑L);
After processing all queries we compute prefix sums of both diff arrays obtaining coeff[i] and const[i]. The answer for city i is coeff[i]·i + const[i]. This runs in O(N+Q) per test case and uses O(N) extra memory.

code.C:
#include <stdio.h>
#include <stdlib.h>
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        int N,Q; scanf("%d %d", &N, &Q);
        long long *coeff = (long long*)calloc(N+3, sizeof(long long));
        long long *cons  = (long long*)calloc(N+3, sizeof(long long));
        for(int i=0;i<Q;i++){
            int L,R; scanf("%d %d", &L, &R);
            coeff[L] += 1; coeff[R+1] -= 1;
            long long c = 1LL - L;
            cons[L] += c; cons[R+1] -= c;
        }
        long long curCoeff=0, curCons=0;
        for(int i=1;i<=N;i++){
            curCoeff += coeff[i];
            curCons  += cons[i];
            long long ans = curCoeff * i + curCons;
            printf("%lld", ans);
            if(i<N) printf(" ");
        }
        printf("\n");
        free(coeff); free(cons);
    }
    return 0;
}

