const fs = require('fs');
const data = fs.readFileSync(0, 'utf-8').trim().split(/\s+/).map(Number);
let idx = 0;
const T = data[idx++];
let output = [];
for (let t = 0; t < T; t++) {
  const N = data[idx++];
  const Q = data[idx++];
  const coeff = new Array(N + 2).fill(0);
  const cons = new Array(N + 2).fill(0);
  for (let i = 0; i < Q; i++) {
    const L = data[idx++];
    const R = data[idx++];
    coeff[L] += 1;
    coeff[R + 1] -= 1;
    const c = 1 - L;
    cons[L] += c;
    cons[R + 1] -= c;
  }
  let curCoeff = 0, curCons = 0;
  let line = [];
  for (let i = 1; i <= N; i++) {
    curCoeff += coeff[i];
    curCons += cons[i];
    line.push(String(curCoeff * i + curCons));
  }
  output.push(line.join(' '));
}
